import React, { useState, useEffect } from 'react';
import axios from 'axios';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [loadingContacts, setLoadingContacts] = useState(false);
  const [accessToken, setAccessToken] = useState(null);
  const [noContactsMessage, setNoContactsMessage] = useState('');
  const [callStatus, setCallStatus] = useState(''); // Mesaj pentru statusul apelului

  const handleLogin = () => {
    window.location.href = 'http://localhost:8000/shortcuts/teams/login/';
  };

  const handleCallback = async () => {
    const queryParams = new URLSearchParams(window.location.search);
    const code = queryParams.get('code');

    if (!code) {
      console.error("Codul de autorizare nu este prezent în URL");
      return;
    }

    try {
      const response = await axios.get(`http://localhost:8000/shortcuts/teams/callback/?code=${code}`);
      const token = response.data.access_token;
      console.log('Token de acces:', token);
      setAccessToken(token);

      window.history.replaceState({}, document.title, window.location.pathname);
    } catch (error) {
      console.error('Eroare la preluarea tokenului de acces:', error);
    }
  };

  useEffect(() => {
    const token = sessionStorage.getItem('access_token');
    if (token) {
      setAccessToken(token);
    } else {
      handleCallback();
    }
  }, []);

  const fetchContacts = async () => {
    setLoadingContacts(true);
    setNoContactsMessage('');
    try {
      const token = accessToken || sessionStorage.getItem('access_token');

      if (!token) {
        setNoContactsMessage('Nu s-a putut obține tokenul de acces.');
        return;
      }

      const response = await axios.get('http://localhost:8000/shortcuts/teams/contacts/', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (response.data.contacts && response.data.contacts.length > 0) {
        setContacts(response.data.contacts);
      } else {
        setNoContactsMessage('Nu sunt contacte disponibile.');
      }
    } catch (error) {
      console.error('Eroare la preluarea contactelor:', error);
      setNoContactsMessage('A apărut o eroare la preluarea contactelor.');
    } finally {
      setLoadingContacts(false);
    }
  };

  const initiateCall = async (contactId) => {
    try {
      const response = await axios.post('http://localhost:8000/shortcuts/teams/initiate-call/', { contact_id: contactId });
      if (response.data.message) {
        setCallStatus(`Apel către contactul ${contactId} inițiat cu succes.`);
      } else {
        setCallStatus('Nu s-a putut iniția apelul.');
      }
    } catch (error) {
      console.error('Eroare la inițierea apelului:', error);
      setCallStatus('A apărut o eroare la inițierea apelului.');
    }
  };

  return (
    <div className="teams-container">
      <h1>Microsoft Teams</h1>
      <button onClick={handleLogin}>Conectare la Microsoft Teams</button>
      <button onClick={fetchContacts}>Preia Contactele</button>

      {loadingContacts && <p>Se încarcă contactele...</p>}
      {noContactsMessage && <p>{noContactsMessage}</p>}

      {accessToken && <p>Access Token: {accessToken}</p>}

      <ul>
        {contacts.map(contact => (
          <li key={contact.id}>
            {contact.displayName}
            <button onClick={() => initiateCall(contact.id)}>Inițiază Apel Audio</button>
          </li>
        ))}
      </ul>

      {callStatus && <p>{callStatus}</p>}
    </div>
  );
};

export default MicrosoftTeams;
